code = """import json
import pandas as pd

# Load results
r1 = locals()['var_function-call-14362589638182063743']
r2 = locals()['var_function-call-1116350553555702663']
r3 = locals()['var_function-call-5682291609611544892']
r4 = locals()['var_function-call-13383296596846785003']
r5 = locals()['var_function-call-7330966903023196170']

results = []
results.extend(r1)
results.extend(r2)
results.extend(r3)
results.extend(r4)
results.extend(r5)

# Load stock info for names
path_stock_info = locals()['var_function-call-6994133641640717647']
with open(path_stock_info, 'r') as f:
    stock_info = json.load(f)

# Map symbol to company name
# Use "Company Description" field but extract name? 
# The field description says: "Company name and description".
# Examples: "Aegon Funding Company LLC is part of..." -> Name is likely at the start.
# "Albany International Corporation specializes in..." -> Name is "Albany International Corporation"
# "Apartment Investment and Management Company specializes in..."
# I should try to extract the name. A simple heuristic: split by " is ", " specializes ", " operates ", " offers ", " provides ".
# Or just return the symbol and full description if extracting is risky.
# The user asked for "names". I will try to provide the cleanest name possible.
# Most descriptions start with the name.

symbol_to_name = {item['Symbol']: item['Company Description'] for item in stock_info}

data = []
for r in results:
    sym = r['Symbol']
    up = r['UpDays']
    down = r['DownDays']
    
    if up == 'nan' or down == 'nan' or up is None or down is None:
        continue
    
    up = float(up)
    down = float(down)
    
    if up > down:
        net = up - down
        data.append({
            'Symbol': sym,
            'UpDays': up,
            'DownDays': down,
            'NetUp': net
        })

# Sort by NetUp desc
df = pd.DataFrame(data)
df = df.sort_values(by='NetUp', ascending=False)
top5 = df.head(5)

# Extract names
final_list = []
for index, row in top5.iterrows():
    sym = row['Symbol']
    desc = symbol_to_name.get(sym, "Unknown")
    # Heuristic to clean name
    # Common separators in the descriptions: " is ", " specializes ", " offers ", " provides ", " operates ", " excels ", " generates "
    separators = [" is ", " specializes ", " offers ", " provides ", " operates ", " excels ", " generates ", " part of ", " commonly known as "]
    name = desc
    for sep in separators:
        if sep in desc:
            name = desc.split(sep)[0]
            break
    
    final_list.append({
        "Symbol": sym,
        "Name": name,
        "UpDays": row['UpDays'],
        "DownDays": row['DownDays'],
        "NetUp": row['NetUp']
    })

print("__RESULT__:")
print(json.dumps(final_list))"""

